class Todo:
    def __init__(self):
        self.connection = sqlite3.connect('todos.db')
        self.cursor = self.connection.cursor()
        self.create_table()

    def create_table(self):
        self.cursor.execute('''CREATE TABLE IF NOT EXISTS todos (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            title TEXT NOT NULL,
            description TEXT,
            completed BOOLEAN DEFAULT FALSE
        )''')

    def add_todo(self, title, description):
        self.cursor.execute("INSERT INTO todos (title, description) VALUES (?, ?)", (title, description))
        self.connection.commit()

    def get_todos(self):
        self.cursor.execute("SELECT * FROM todos")
        return self.cursor.fetchall()

    def update_todo(self, id, title=None, description=None, completed=None):
        set_clause = []
        values = []

        if title:
            set_clause.append('title=?')
            values.append(title)
        if description:
            set_clause.append('description=?')
            values.append(description)
        if completed is not None:
            set_clause.append('completed=?')
            values.append(completed)

        if len(set_clause) == 0:
            raise ValueError("At least one field must be provided for update")

        set_clause_str = ', '.join(set_clause)
        placeholders = ', '.join(['?'] * len(values))

        self.cursor.execute(f"UPDATE todos SET {set_clause_str} WHERE id=?", values)
        self.connection.commit()

    def remove_todo(self, id):
        self.cursor.execute("DELETE FROM todos WHERE id=?", (id,))
        self.connection.commit()

    def close(self):
        self.connection.close()

    def revoke_constraint(self, constraint_name):
        if constraint_name is None:
            raise ValueError("Constraint name must be provided")

        self.cursor.execute(f"PRAGMA foreign_key_check = OFF")
        self.cursor.execute(f"ALTER TABLE todos DROP CONSTRAINT {constraint_name}")
        self.cursor.execute(f"PRAGMA foreign_key_check = ON")
        self.connection.commit()

    def allow_classes(self):
        self.revoke_constraint('no-classes')

